static double l2_norm(const double *v, int n) {
    double s = 0.0;
    for (int i = 0; i < n; i++) {
        s += v[i] * v[i];
    }
    return sqrt(s);
}

int run_u(const CaseSpec *spec, const char *out_dir, SolveResult *out) {
    MatrixView view;
    BsrPack pack;
    double rhs[MAX_DIM];
    double x[MAX_DIM];
    double r[MAX_DIM];
    double true_res;
    double rep_res;
    int hit;
    int iters;

